export interface SectionInfo {
  type: string;
  startLine: number;
  endLine: number;
}

/** Our top-level block spans (heading scoping flattened away). */
export function topLevelSpans(doc: OutlineDoc): SectionInfo[] {
  const out: SectionInfo[] = [];
